@startuml
skinparam packageStyle rectangle
skinparam shadowing false
skinparam classAttributeIconSize 0

package "com" {
  package "iluwatar" {
    package "prototype" {

      class ElfBeast << (C,#BFE3BF) >> {
        +ElfBeast()
        +clone() : Beast
        +toString() : String
      }

      class OrcBeast << (C,#BFE3BF) >> {
        +OrcBeast()
        +clone() : Beast
        +toString() : String
      }

      class ElfWarlord << (C,#BFE3BF) >> {
        +ElfWarlord()
        +clone() : Warlord
        +toString() : String
      }

      class OrcWarlord << (C,#BFE3BF) >> {
        +OrcWarlord()
        +clone() : Warlord
        +toString() : String
      }

      class ElfMage << (C,#BFE3BF) >> {
        +ElfMage()
        +clone() : Mage
        +toString() : String
      }

      class OrcMage << (C,#BFE3BF) >> {
        +OrcMage()
        +clone() : Mage
        +toString() : String
      }

      class App << (C,#BFE3BF) >> {
        +App()
        +main(args : String[])
      }

      abstract class Beast << (A,#BFEFFF) >> {
        +Beast()
        +clone() : Beast
      }

      abstract class Warlord << (A,#BFEFFF) >> {
        +Warlord()
        +clone() : Warlord
      }

      abstract class Mage << (A,#BFEFFF) >> {
        +Mage()
        +clone() : Mage
      }

      abstract class Prototype << (A,#BFEFFF) >> {
        +Prototype()
        +clone() : Object
      }

      interface HeroFactory << (I,#D7C7FF) >> {
        +createBeast() : Beast
        +createMage() : Mage
        +createWarlord() : Warlord
      }

      class HeroFactoryImpl << (C,#BFE3BF) >> {
        -beast : Beast
        -mage : Mage
        -warlord : Warlord
        +HeroFactoryImpl(mage : Mage, warlord : Warlord, beast : Beast)
        +createBeast() : Beast
        +createMage() : Mage
        +createWarlord() : Warlord
      }

      ElfBeast -|> Beast
      OrcBeast -|> Beast

      ElfWarlord -|> Warlord
      OrcWarlord -|> Warlord

      ElfMage -|> Mage
      OrcMage -|> Mage

      Beast -|> Prototype
      Warlord -|> Prototype
      Mage -|> Prototype

      HeroFactoryImpl ..|> HeroFactory

      HeroFactoryImpl --> Beast : -beast
      HeroFactoryImpl --> Warlord : -warlord
      HeroFactoryImpl --> Mage : -mage

    }
  }
}
@enduml
